def gen(rng, size):
    n = max(1, min(size, 300))
    vals = rng.sample(range(-3000, 3001), n)
    # assign values to a random binary tree shape by recursive split
    def build(vs):
        if not vs:
            return None
        i = rng.randrange(len(vs))
        return (vs[i], build(vs[:i]), build(vs[i+1:]))
    root = build(vals)
    pre, ino = [], []
    def pr(t):
        if t is None:
            return
        pre.append(t[0]); pr(t[1]); pr(t[2])
    def io(t):
        if t is None:
            return
        io(t[1]); ino.append(t[0]); io(t[2])
    pr(root); io(root)
    return [pre, ino]

