class Solution:
    def buildTree(self, preorder, inorder):
        # Brute force: no index map, linear search + list slicing each level.
        def build(pre, ino):
            if not pre:
                return None
            root_val = pre[0]
            k = ino.index(root_val)
            node = TreeNode(root_val)
            node.left = build(pre[1:1 + k], ino[:k])
            node.right = build(pre[1 + k:], ino[k + 1:])
            return node
        return build(preorder, inorder)

