class Solution:
    def buildTree(self, preorder, inorder):
        idx = {v: i for i, v in enumerate(inorder)}
        self.pre = 0
        def build(lo, hi):
            if lo > hi:
                return None
            root_val = preorder[self.pre]
            self.pre += 1
            node = TreeNode(root_val)
            mid = idx[root_val]
            node.left = build(lo, mid - 1)
            node.right = build(mid + 1, hi)
            return node
        return build(0, len(inorder) - 1)

